public int[] prisonAfterNDays(int[] cells, int n) {
    int[] temp = new int[8];
    n = n % 14 == 0 ? 14 : n % 14; // Pattern repeats every 14 days

    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j < 7; ++j) {
            temp[j] = cells[j - 1] == cells[j + 1] ? 1 : 0;
        }
        cells = temp.clone();
    }

    return cells;
}
```

